function toggleExclusiveAccordion(targetSection) {
  const sections = [wrongScanSection, completedHistorySection, advancedTools];
  const shouldOpen = !targetSection.classList.contains("open");

  sections.forEach((section) => {
    const isTarget = section === targetSection;
    section.classList.toggle("open", isTarget && shouldOpen);
    const toggle = section.querySelector(".accordion-toggle");
    if (toggle) {
      toggle.setAttribute("aria-expanded", String(isTarget && shouldOpen));
    }
  });
}
